        if a.isdigit() and b.isdigit(): result = (int(a) > int(b)) - (int(a) < int(b))
        elif a.isdigit(): return -1
        elif b.isdigit(): return 1
        else: result = (a > b) - (a < b)
        if result: return result
    return (len(left) > len(right)) - (len(left) < len(right))
def compare_semver(left: str, right: str) -> int:
